import{_ as e,o as t,c as s,ac as i}from"./chunks/framework.DnBnwVZk.js";const g=JSON.parse('{"title":"解决Mac OS系统IDEA同步配置SSH登陆Git仓库报错问题","description":"","frontmatter":{"date":"2021-05-18T15:26:01.000Z","categories":["知识&技巧"],"tags":["IDEA"],"publish":true},"headers":[],"relativePath":"views/java/knowledge/IDEASyncSettings.md","filePath":"views/java/knowledge/IDEASyncSettings.md","lastUpdated":1775803235000}'),n={name:"views/java/knowledge/IDEASyncSettings.md"};function r(o,a,c,d,p,l){return t(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1621351561000"},[...a[0]||(a[0]=[i(`<h1 id="解决mac-os系统idea同步配置ssh登陆git仓库报错问题" tabindex="-1">解决Mac OS系统IDEA同步配置SSH登陆Git仓库报错问题 <a class="header-anchor" href="#解决mac-os系统idea同步配置ssh登陆git仓库报错问题" aria-label="Permalink to &quot;解决Mac OS系统IDEA同步配置SSH登陆Git仓库报错问题&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>IDEA提供了配置同步的功能，支持将配置保存到Git仓库，然后各台电脑/系统上的客户端自动同步仓库中的配置，入口如下：</p><p><img src="https://cdn.jsdmirror.com/gh/kkyeer/picbed/20210518165623.png" alt="20210518165623"></p><p>使用说明见<a href="https://www.jetbrains.com/help/idea/sharing-your-ide-settings.html" target="_blank" rel="noreferrer">官方文档</a></p><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>在新版Mac OS系统下（我的是11.2），新生成ssh key并在远程Git仓库配置ssh授权，确认本地用户可以正常ssh登陆到服务器，Git Clone也正常，但是在上述IDEA配置中填入SSH登陆的仓库的时候，会提示需要登录服务器</p><p><img src="https://cdn.jsdmirror.com/gh/kkyeer/picbed/20210518170040.png" alt="20210518170040"></p><p>idea日志如下</p><p><img src="https://cdn.jsdmirror.com/gh/kkyeer/picbed/20210518171123.png" alt="20210518171123"></p><h2 id="原因" tabindex="-1">原因 <a class="header-anchor" href="#原因" aria-label="Permalink to &quot;原因&quot;">​</a></h2><p>Mac OS的ssh组件进行了升级，默认生成高版本的key，特征是私钥的开头为<code>-----BEGIN OPENSSH PRIVATE KEY-----</code><img src="https://cdn.jsdmirror.com/gh/kkyeer/picbed/20210518171958.png" alt="20210518171958"></p><p>IDEA的Settings Repository插件使用的JSch组件不支持此key，导致报错</p><h2 id="解决" tabindex="-1">解决 <a class="header-anchor" href="#解决" aria-label="Permalink to &quot;解决&quot;">​</a></h2><ol><li>新生成旧版本的密钥对，可以考虑不覆盖原有的密钥对，如果不覆盖，需要执行第2步，否则不需要:命令行执行<code>ssh-keygen -t rsa -m PEM</code>，并在对应的Git仓库配置授权</li><li>如果密钥对不是默认的<code>id_rsa</code>，则在<code>.ssh</code>文件夹下新建config文件，配置内容如下：</li></ol><div class="language-config vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">config</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host github.com&lt;你的Git仓库域名&gt;</span></span>
<span class="line"><span>  HostName github.com&lt;你的Git仓库域名&gt;</span></span>
<span class="line"><span>  IdentityFile ~/.ssh/id_rsa_old&lt;这里填你刚生成的密钥对前缀&gt;</span></span>
<span class="line"><span>  User git&lt;这里填SSH的用户名&gt;</span></span></code></pre></div><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p><a href="https://youtrack.jetbrains.com/issue/IDEA-215839" target="_blank" rel="noreferrer">IDEA官方Bug</a></p>`,18)])])}const m=e(n,[["render",r]]);export{g as __pageData,m as default};
